var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"저것 좀 봐. 쟤 또 물건 망가트렸어.","JPN":"ほら、あれ見てみなよ。あいつ、また物を壊したよ。","ENG":"Look at that. She ruined it again.","TWN":"你看啦，那傢伙又把東西弄壞了。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"케이시는 카운터라며? 카운터랑은 살짝 부딪히기만 해도 병원에 실려간대.","JPN":"ケイシーはカウンターなんでしょ？　カウンターとはちょっとぶつかっただけでも入院って聞いた。","ENG":"Kaci's a Counter, right? They say if you bump into a Counter that you get sent to the hospital.","TWN":"卡西不是制裁者嗎？聽說只要稍微撞到制裁者，就會被送進醫院。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"가까이 가지 말자. 같이 있으면 우리도 다칠 거야.","JPN":"近付いちゃだめ。一緒にいたら、私たちも怪我するよ。","ENG":"Let's stay away from her. If we play with her, we'll get hurt too.","TWN":"別靠近她啦，跟她在一起我們也會受傷。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"케이시, 이건 모두 널 위해 결정된 거란다.","JPN":"ケイシー、これは全部あなたのための決定なの。","ENG":"Kaci, this is all for your own good.","TWN":"卡西，這一切都是為了你好才做的決定。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"네가 실수로라도 친구들을 다치게 한다면… 너도 많이 힘들어질 테니까. 이해하지?","JPN":"ケイシーが間違って友だちを傷つけてしまったら……きっと、自分自身にも耐えられなくなると思うの。わかってもらえるよね？","ENG":"If you accidentally hurt your friends... it'll become difficult for you too. Do you understand?","TWN":"要是你不小心傷到朋友……你自己也會很痛苦，懂嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"전 괜찮아요.","JPN":"あたしは大丈夫です。","ENG":"I'm all right.","TWN":"我沒關係。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 누구도 다치게 하지 않아.","JPN":"あたしは誰も傷つけない。","ENG":"I don't hurt anyone.","TWN":"我不會傷害任何人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"이것 봐. 이렇게 연약한 식물들도 전부 잘 키워냈는걸?","JPN":"ほら、こんなに弱い植物だって上手に育ててみせたもの。","ENG":"Look at this. I managed to take care of and grow all these plants!","TWN":"你看，就連這麼脆弱的植物，我也都好好地養大了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"어쩌면… 이대로 아무도 몰라줘도 괜찮을 거야.","JPN":"もしかすると……このまま誰にもわかってもらえないかもしれないけど、大丈夫。","ENG":"Maybe... It doesn't matter if no one understands me.","TWN":"或許……就算沒有人理解我也沒關係。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게 예쁘게 피어난 꽃들이… 내 마음을 이해해주고 있으니까.","JPN":"こんなに綺麗に咲き誇った花たちが……あたしの気持ちを理解してくれている。","ENG":"These beautifully bloomed flowers... they get me.","TWN":"因為這些盛開得如此漂亮的花……它們懂我的心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"파견 실습…?","JPN":"派遣実習……？","ENG":"On-the-job training...?","TWN":"派遣實習……？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그래! 브라우니 선생님이 이번엔 태스크포스 견학이 아니라 실습생으로 가는 거래!","JPN":"そう！　ブラウニー先生に聞いたけど、今回はタスクフォースの見学じゃなくて実習なんだって！","ENG":"Yup! Ms. Brownie said that someone will go to a TASKFORCE as a trainee and not just for a tour!","TWN":"對啊！布朗尼老師這次不是去參觀特遣勢力，而是要去實習！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"초등부에선 딱 한 명만 선발한다니까, 이건 두 번 다신 없을 기회라구, 케이시!","JPN":"初等部では1人しか選抜しないって！　つまり、絶好のチャンスってことだよ、ケイシー！","ENG":"They are selecting only one person from the elementary school, so this is a once in a lifetime chance, Kaci!","TWN":"而且小學部只選一個人，這可是一輩子只有一次的機會耶，卡西！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"정말로… 내가 그런 곳에 가는 게 도움이 될까?","JPN":"本当に……あたしがそんなとこに行って役に立つかな？","ENG":"But will I... be of any help over there?","TWN":"我去那種地方……真的能幫上忙嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"물론이지! 히어로가 되려면 연습보단 실전 경험이 중요한 법이니까!","JPN":"もちろん！　ヒーローになるためには、練習よりも実戦の経験が大事って言うじゃん！","ENG":"Of course, you will! Experience is more important than practice if you want to become a hero!","TWN":"當然會啊！如果要成為英雄，比起練習，實戰經驗最重要了！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그렇게 해서, 우리 데이마인에 일일 파견 실습생으로 오게 된 아카데미의 케이시 빈즈 학생이다.","JPN":"というわけで、アカデミーからこのデイマインに一日実習生として派遣された、ケイシー・ビンズさんだ。","ENG":"And so, Academy's Kaci Bins will be here with us at Daymine as a one-day trainee.","TWN":"那麼，這位就是今天來到我們戴瑪因擔任一日派遣實習生的學院學生卡西‧比恩茲。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기… 잘 부탁드립니다.","JPN":"あの……よろしくお願いします。","ENG":"Uh... Pleased to meet you all.","TWN":"那個……請多指教。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"와아, 이렇게 키 작고 귀여운 꼬마애가 저희 회사의 일일 사원이라니- 너무 좋은데요?","JPN":"わあ、こんなに小さくて可愛い子どもがうちの一日社員だなんて！　嬉しいです！","ENG":"Wow! This little cutie pie is going to be an employee at our company for the day? That's wonderful!","TWN":"哇，這麼小隻又可愛的孩子，竟然是我們公司的臨時員工，也太棒了吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"그렇게 말씀을 함부로 하시면 곤란합니다, 소미 씨! 키가 작다거나, 귀엽다는 표현을 직접적으로 쓰면 불쾌해하는 분도 계시다고요!","JPN":"ミウラさん、言葉には気をつけましょう。小さいとか可愛いという表現を不快に思う方もいるんですから！","ENG":"You shouldn't talk to her like that, Somi! Some people might be offended if they are called little or cute!","TWN":"請不要這樣隨便亂說，小美小姐！直接說人家小隻或可愛，有些人會感到不舒服！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"으왓…! 그렇다면 방금 전 엄청난 실례를 한 건가요?!","JPN":"うわ……！　じゃあ私は今とんでもない失言をしたんですか！？","ENG":"Oops...! Then, was I incredibly rude just now?!","TWN":"嗚哇……！那我剛剛是不是超級失禮了？！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아뇨. 전 키가 작은 게 맞는 걸요.","JPN":"いえ、あたしが小さいのは本当ですし。","ENG":"No. It's true that I'm little.","TWN":"沒關係，我本來就很矮。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"귀엽다는 표현도… 칭찬이라고 생각해요.","JPN":"可愛いという表現も……褒め言葉だと思います。","ENG":"And I think being called cute is... a compliment.","TWN":"可愛這個詞……我也覺得是稱讚。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"휴우… 그렇다면 다행입니다.","JPN":"ふう……それならよかったです。","ENG":"Phew... That's a relief.","TWN":"呼……那就好。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"하하- 제 늦둥이 사촌 여동생도 딱 이 정도 나이인데, 정말 깜찍하다니까요.","JPN":"はは、僕の従妹もちょうど同じぐらいの年齢で、本当に可愛いんですよ。","ENG":"Haha, my youngest cousin is around your age, and she's just the cutest.","TWN":"哈哈—我最小的表妹也差不多這個年紀，真的超可愛的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"헤헤- 언니랑 사탕 먹으러 갈까?","JPN":"えへへ、お姉ちゃんと一緒にアメ食べない？","ENG":"Hehe, do you want to go get a lollipop with me?","TWN":"嘿嘿—要不要跟姐姐去吃糖果？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 저기…","JPN":"あ……えっと……","ENG":"Uh... Um...","TWN":"啊……那個……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"정신 차려. 지금은 업무시간이다.","JPN":"おしゃべりはそのくらいで。今は業務時間だ。","ENG":"Stop fooling around. You're on the clock.","TWN":"正經點，現在是上班時間。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};